const item = $input.first().json;
const body = item.body ?? item;
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!body || typeof body !== 'object') throw new Error('Invalid body');
if (typeof body.session_id !== 'string' || !uuidRe.test(body.session_id)) throw new Error('Invalid session_id');
if (typeof body.message !== 'string' || body.message.length === 0 || body.message.length > 1000) throw new Error('Invalid message');
return [{ json: {
  session_id: body.session_id,
  message: body.message,
  user_metadata: body.user_metadata ?? null,
  received_at: new Date().toISOString(),
} }];

const agentData = $json;
let reply = (agentData.output || agentData.text || '').toString();
// Sanitize: remove zero-width chars (modelo free a veces los emite)
reply = reply.replace(/[\u200B-\u200D\uFEFF\u2060]/g, '');
reply = reply.replace(/\s{3,}/g, ' ').trim();
if (reply.length < 3) {
  reply = 'Te comparto la informacion solicitada.';
}
const attachments = [];
const steps = agentData.intermediateSteps || [];

function pushAttachment(p) {
  if (!p || typeof p !== 'object') return;
  if (p.type === 'image' && p.url) {
    attachments.push({ type: 'image', url: p.url, caption: p.caption });
  } else if (p.type === 'image_floating' && p.url) {
    attachments.push({ type: 'image_floating', url: p.url, caption: p.caption, title: p.title });
  } else if (p.type === 'gallery' && Array.isArray(p.images)) {
    attachments.push({ type: 'gallery', images: p.images });
  } else if (p.type === 'gallery_floating' && Array.isArray(p.images)) {
    attachments.push({ type: 'gallery_floating', images: p.images, caption: p.caption });
  } else if (p.type === 'masterplan_floating' && p.url) {
    attachments.push({ type: 'masterplan_floating', url: p.url, caption: p.caption, title: p.title });
  } else if (p.type === 'tour360_floating' && p.url) {
    attachments.push({ type: 'tour360_floating', url: p.url, caption: p.caption, title: p.title, poster: p.poster });
  } else if (p.type === 'whatsapp_link' && p.url) {
    attachments.push({ type: 'whatsapp_link', url: p.url, label: p.label || 'Hablar con equipo de ventas por WhatsApp' });
  }
}

for (const step of steps) {
  const obs = step.observation ?? step.toolOutput ?? step;
  let parsed = obs;
  if (typeof obs === 'string') {
    try { parsed = JSON.parse(obs); } catch { continue; }
  }
  if (Array.isArray(parsed)) {
    for (const item of parsed) {
      const unwrapped = item && item.json ? item.json : item;
      pushAttachment(unwrapped);
    }
  } else {
    const unwrapped = parsed && parsed.json ? parsed.json : parsed;
    pushAttachment(unwrapped);
  }
}
return [{ json: { reply, attachments } }];
